function largest(arr) {
  return arr.reduce((max, curr) => curr > max ? curr : max, -Infinity);
}

function largestTyped(arr) {
  const typed = new Float64Array(arr);
  let max = -Infinity;
  for (let i = 0; i < typed.length; i++) {
    if (typed[i] > max) max = typed[i];
  }
  return max;
}
